const response = $input.first().json;

const decisions = Array.isArray(response) ? response : (response.decisions || response.data || []);

const reviewData = decisions.map(d => {
  const name = d.strategyName || d.strategy || d.name || 'Unknown';
  const decision = (d.decision || d.action || 'TRADE').toUpperCase();
  const reason = d.reason || d.rationale || '';
  const outcome = d.outcome || d.result || null;
  const pnl = d.pnl !== undefined ? d.pnl : null;
  const hasOutcome = outcome !== null || pnl !== null;

  return {
    name,
    decision,
    reason,
    outcome,
    pnl,
    hasOutcome
  };
});

return [{
  json: {
    reviewData,
    totalDecisions: reviewData.length,
    withOutcomes: reviewData.filter(r => r.hasOutcome).length,
    withoutOutcomes: reviewData.filter(r => !r.hasOutcome).length,
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;
const reviews = data.reviewData;

let correctSkips = 0;
let falseSkips = 0;
let correctTrades = 0;
let missedSaves = 0;
let noOutcomeCount = 0;

for (const r of reviews) {
  if (!r.hasOutcome) {
    noOutcomeCount++;
    continue;
  }

  const wasSkipped = r.decision === 'SKIP';
  const wasReduced = r.decision === 'REDUCE';
  const wouldHaveLost = r.pnl !== null ? r.pnl < 0 : (r.outcome === 'LOSS' || r.outcome === 'LOSER');
  const wouldHaveWon = r.pnl !== null ? r.pnl >= 0 : (r.outcome === 'WIN' || r.outcome === 'WINNER');

  if (wasSkipped && wouldHaveLost) {
    correctSkips++;
  } else if (wasSkipped && wouldHaveWon) {
    falseSkips++;
  } else if (!wasSkipped && wouldHaveWon) {
    correctTrades++;
  } else if (!wasSkipped && wouldHaveLost) {
    missedSaves++;
  }
}

const totalWithOutcome = correctSkips + falseSkips + correctTrades + missedSaves;
const skipAccuracy = (correctSkips + falseSkips) > 0
  ? ((correctSkips / (correctSkips + falseSkips)) * 100).toFixed(1)
  : 'N/A';
const tradeAccuracy = (correctTrades + missedSaves) > 0
  ? ((correctTrades / (correctTrades + missedSaves)) * 100).toFixed(1)
  : 'N/A';

return [{
  json: {
    metrics: {
      correctSkips,
      falseSkips,
      correctTrades,
      missedSaves,
      skipAccuracy: skipAccuracy + '%',
      tradeAccuracy: tradeAccuracy + '%',
      totalWithOutcome,
      noOutcomeCount
    },
    reviewData: data.reviewData,
    timestamp: data.timestamp
  }
}];

const data = $input.first().json;
const m = data.metrics;
const today = new Date().toISOString().split('T')[0];

const strategyLines = [];
for (const r of data.reviewData) {
  let outcomeStr = 'No outcome recorded';
  if (r.hasOutcome) {
    outcomeStr = r.pnl !== null ? 'PnL: $' + String(r.pnl) : 'Outcome: ' + String(r.outcome);
  }
  strategyLines.push('  - ' + r.name + ' [' + r.decision + ']: ' + outcomeStr);
}
const strategyDetails = strategyLines.join('\n');

const summaryLines = [
  'Correct Skips: ' + String(m.correctSkips) + ' (avoided losers)',
  'False Skips: ' + String(m.falseSkips) + ' (missed winners)',
  'Correct Trades: ' + String(m.correctTrades) + ' (traded winners)',
  'Missed Saves: ' + String(m.missedSaves) + ' (traded losers, should have skipped)'
];

const message = 'Skip Accuracy: ' + String(m.skipAccuracy) + ' | Trade Accuracy: ' + String(m.tradeAccuracy) + '\n\n' +
  summaryLines.join('\n') + '\n\nStrategy Details:\n' + strategyDetails;

return [{
  json: {
    title: 'Post-Session Skip Review (' + today + ')',
    message: message,
    severity: 'info',
    data: {
      date: today,
      skipAccuracy: String(m.skipAccuracy),
      tradeAccuracy: String(m.tradeAccuracy),
      correctSkips: String(m.correctSkips),
      falseSkips: String(m.falseSkips),
      correctTrades: String(m.correctTrades),
      missedSaves: String(m.missedSaves)
    }
  }
}];

